const sd = $getWorkflowStaticData('global');
if (!sd.chats) sd.chats = {};
const inp = $input.first().json;
const isCb = !!inp.callback_query;
const chatId = String(isCb ? inp.callback_query.message.chat.id : inp.message?.chat?.id);
const text = isCb ? '' : (inp.message?.text || '').trim();
const cb = isCb ? inp.callback_query.data : '';
const st = sd.chats[chatId] || {};
const r = { action:'reply', chatId, text:'', kb:null, title:'', type:'', subType:'', raw:'', cId:'', ratio:'', ages:'', thinkers:'', pov:'' };
const MENU = [[{text:'Buat Konten',callback_data:'m_create'},{text:'Cek Status',callback_data:'m_status'}],[{text:'Submit Review',callback_data:'m_submit'},{text:'Prompt Thumbnail',callback_data:'m_thumb'}],[{text:'Buka Web Adably',url:'https:
const TYPES = [[{text:'QNA',callback_data:'t_QNA'},{text:'Artikel',callback_data:'t_ARTICLE'}],[{text:'Pembelajaran',callback_data:'t_PEMBELAJARAN'},{text:'Kisah',callback_data:'t_KISAH'}],[{text:'Kembali',callback_data:'m_main'}]];
const KISAH_MENU = [[{text:'Sirah Nabawiyah',callback_data:'k_SIRAH'}],[{text:'Qashashul Anbiya',callback_data:'k_QASHASH'}],[{text:'Teladan Sahabat',callback_data:'k_TELADAN'}],[{text:'Cerita Fiksi',callback_data:'k_FIKSI'}],[{text:'Kembali',callback_data:'m_create'}]];
const POV_MENU = [[{text:'Perspektif Orang Tua',callback_data:'pov_ORTU'}],[{text:'Perspektif Anak',callback_data:'pov_ANAK'}],[{text:'Kembali',callback_data:'m_create'}]];
const RATIO_MENU = [[{text:'16:9 Website',callback_data:'r_16:9'}],[{text:'1:1 IG/FB',callback_data:'r_1:1'}],[{text:'4:5 IG Optimal',callback_data:'r_4:5'}],[{text:'Kembali',callback_data:'m_main'}]];
function ageKb(selected) {
  const ages = ['3-5','5-7','7-10','10-13','Semua Usia'];
  const rows = [];
  const row1 = [];
  const row2 = [];
  ages.forEach((a,i) => {
    const sel = selected.includes(a);
    const btn = {text:(sel?'✅ ':'')+a+(a!=='Semua Usia'?' thn':''), callback_data:'age_'+a};
    if (i < 2) row1.push(btn);
    else if (i < 4) row2.push(btn);
    else rows.push([btn]);
  });
  rows.unshift(row2);
  rows.unshift(row1);
  if (selected.length > 0) rows.push([{text:'Lanjut ➡️',callback_data:'age_done'}]);
  rows.push([{text:'Kembali',callback_data:'m_create'}]);
  return rows;
}
function thinkerKb(selected) {
  const T = [
    {id:'aristotle',label:'Aristotle',cat:'Sistematis'},
    {id:'descartes',label:'Descartes',cat:'Sistematis'},
    {id:'musk',label:'Elon Musk',cat:'Sistematis'},
    {id:'feynman',label:'Feynman',cat:'Analogi'},
    {id:'sagan',label:'Carl Sagan',cat:'Analogi'},
    {id:'suntzu',label:'Sun Tzu',cat:'Strategi'},
    {id:'thiel',label:'Peter Thiel',cat:'Strategi'},
    {id:'grove',label:'Andrew Grove',cat:'Strategi'},
    {id:'anies',label:'Anies B.',cat:'Narasi'},
    {id:'nadiem',label:'Nadiem M.',cat:'Narasi'},
    {id:'gladwell',label:'Gladwell',cat:'Narasi'},
  ];
  const rows = [];
  let lastCat = '';
  let row = [];
  T.forEach(t => {
    if (t.cat !== lastCat) {
      if (row.length) rows.push(row);
      row = [];
      lastCat = t.cat;
    }
    const sel = selected.includes(t.id);
    row.push({text:(sel?'✅ ':'')+t.label, callback_data:'th_'+t.id});
    if (row.length === 3) { rows.push(row); row = []; }
  });
  if (row.length) rows.push(row);
  rows.push([{text:'Skip (tanpa thinker)',callback_data:'th_skip'},{text:'Lanjut ➡️',callback_data:'th_done'}]);
  rows.push([{text:'Kembali',callback_data:'m_create'}]);
  return rows;
}
if (isCb) {
  if (cb.startsWith('age_') && st.step === 'select_age') {
    if (cb === 'age_done') {
      sd.chats[chatId] = {...st, step:'select_thinker', thinkers:[]};
      r.text = 'Step 4/5: Pilih Thinker Persona\n\nPilih kerangka berpikir untuk prompt (bisa lebih dari 1):';
      r.kb = thinkerKb([]);
    } else {
      const age = cb.replace('age_','');
      let sel = [...(st.selectedAges||[])];
      if (age === 'Semua Usia') { sel = sel.includes(age) ? [] : ['Semua Usia']; }
      else { sel = sel.filter(a=>a!=='Semua Usia'); sel.includes(age) ? sel=sel.filter(a=>a!==age) : sel.push(age); }
      sd.chats[chatId] = {...st, selectedAges:sel};
      r.text = 'Step 3/5: Pilih Kelompok Usia\n\nDipilih: '+(sel.length?sel.join(', '):'(belum ada)')+'\n\nKlik usia untuk toggle, lalu klik Lanjut:';
      r.kb = ageKb(sel);
    }
  }
  else if (cb.startsWith('th_') && st.step === 'select_thinker') {
    if (cb === 'th_done' || cb === 'th_skip') {
      const thinkers = cb === 'th_skip' ? [] : (st.thinkers||[]);
      sd.chats[chatId] = {...st, step:'wait_title', thinkers};
      r.text = 'Step 5/5: Ketik Judul\n\nTipe: '+st.type+(st.sub?' ('+st.sub+')':'')+(st.pov?' | POV: '+st.pov:'')+'\nUsia: '+(st.selectedAges||[]).join(', ')+'\nThinker: '+(thinkers.length?thinkers.join(', '):'(tanpa thinker)')+'\n\nSilakan ketik judul konten:';
    } else {
      const tid = cb.replace('th_','');
      let sel = [...(st.thinkers||[])];
      sel.includes(tid) ? sel=sel.filter(x=>x!==tid) : sel.push(tid);
      sd.chats[chatId] = {...st, thinkers:sel};
      r.text = 'Step 4/5: Pilih Thinker Persona\n\nDipilih: '+(sel.length?sel.join(', '):'(belum ada)')+'\n\nKlik untuk toggle, lalu Lanjut:';
      r.kb = thinkerKb(sel);
    }
  }
  else if (cb.startsWith('pov_')) {
    const pov = cb.replace('pov_','');
    sd.chats[chatId] = {...st, step:'select_age', pov, selectedAges:[]};
    r.text = 'Step 3/5: Pilih Kelompok Usia\n\nKlik usia yang diinginkan (bisa lebih dari 1):';
    r.kb = ageKb([]);
  }
  else {
    switch(cb) {
      case 'm_main': delete sd.chats[chatId]; r.text='Menu Utama - Pilih menu:'; r.kb=MENU; break;
      case 'm_create': r.text='Step 1/5: Pilih Tipe Konten'; r.kb=TYPES; break;
      case 'm_status': sd.chats[chatId]={step:'wait_status_id'}; r.text='Ketik ID konten:'; break;
      case 'm_submit': sd.chats[chatId]={step:'wait_submit_id'}; r.text='Ketik ID konten untuk review:'; break;
      case 'm_thumb': r.text='Pilih rasio thumbnail:'; r.kb=RATIO_MENU; break;
      case 'm_help': r.text='Panduan Adably Bot\n\n1. Buat Konten > pilih tipe\n2. Pilih usia target\n3. Pilih thinker persona\n4. Ketik judul > bot kirim prompt\n5. Copy prompt > paste ke Gemini\n6. Kirim hasil Gemini ke bot\n7. Bot simpan ke DRAFT\n8. Klik Submit Review'; r.kb=[[{text:'Kembali',callback_data:'m_main'}]]; break;
      case 't_QNA': case 't_PEMBELAJARAN':
        { const tp=cb.replace('t_','');
          sd.chats[chatId]={step:'select_age',type:tp,selectedAges:[]};
          r.text='Step 2/5: Tipe dipilih: '+tp+'\n\nPilih kelompok usia (bisa lebih dari 1):';
          r.kb=ageKb([]); break; }
      case 't_ARTICLE':
        sd.chats[chatId]={step:'select_pov',type:'ARTICLE'};
        r.text='Step 2/5: Pilih Perspektif Artikel'; r.kb=POV_MENU; break;
      case 't_KISAH': r.text='Step 2/5: Pilih sub-tipe Kisah:'; r.kb=KISAH_MENU; break;
      case 'k_SIRAH': case 'k_QASHASH': case 'k_TELADAN': case 'k_FIKSI':
        { const ks=cb.replace('k_','');
          sd.chats[chatId]={step:'select_age',type:'KISAH',sub:ks,selectedAges:[]};
          r.text='Step 2/5: Kisah: '+ks+'\n\nPilih kelompok usia:';
          r.kb=ageKb([]); break; }
      case 'r_16:9': case 'r_1:1': case 'r_4:5':
        { const rt=cb.replace('r_','');
          sd.chats[chatId]={step:'wait_thumb_title',ratio:rt};
          r.text='Rasio: '+rt+'\n\nKetik judul/tema thumbnail:'; break; }
      default:
        if(cb.startsWith('submit_')){r.action='submit';r.cId=cb.replace('submit_','');}
        else if(cb.startsWith('status_')){r.action='status';r.cId=cb.replace('status_','');}
        else{r.text='Perintah tidak dikenali.';r.kb=MENU;}
    }
  }
} else if (text === '/start' || text === '/menu') {
  delete sd.chats[chatId];
  r.text='Assalamualaikum!\n\nSaya Adably Content Bot.\nAsisten pembuatan konten islami anak.\n\nPilih menu:'; r.kb=MENU;
} else if (st.step === 'wait_title') {
  r.action='gen_prompt';
  r.type=st.type; r.subType=st.sub||''; r.title=text;
  r.ages=(st.selectedAges||[]).join(',');
  r.thinkers=(st.thinkers||[]).join(',');
  r.pov=st.pov||'';
  r.text='Sedang membuat prompt untuk: '+text+'\nMohon tunggu...';
  sd.chats[chatId]={step:'wait_content',type:st.type,sub:st.sub,title:text};
} else if (st.step === 'wait_content') {
  r.action='save'; r.type=st.type; r.subType=st.sub||''; r.title=st.title; r.raw=text;
  delete sd.chats[chatId];
} else if (st.step === 'wait_thumb_title') {
  r.action='gen_thumb'; r.ratio=st.ratio; r.title=text;
  delete sd.chats[chatId];
} else if (st.step === 'wait_status_id') {
  r.action='status'; r.cId=text.trim(); delete sd.chats[chatId];
} else if (st.step === 'wait_submit_id') {
  r.action='submit'; r.cId=text.trim(); delete sd.chats[chatId];
} else {
  r.text='Ketik /start untuk memulai, atau pilih menu:'; r.kb=MENU;
}
return [{json:r}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
let prompt = '';
if (res.prompt) { prompt = res.prompt; }
else if (res.message) { prompt = 'Error dari API: ' + res.message; }
else { prompt = 'Error: Tidak bisa generate prompt. Pastikan backend sudah di-deploy.'; }
const chatId = prev.chatId;
const msgs = [];
const header = 'PROMPT ' + (prev.type||'') + (prev.subType ? ' ('+prev.subType+')' : '') + '\nJudul: ' + (prev.title||'') + '\n\n';
const footer = '\n\n---\nCopy seluruh prompt di atas, paste ke Gemini/ChatGPT.\nKirim hasilnya ke sini untuk disimpan.';
const full = header + prompt + footer;
if (full.length <= 4096) {
  msgs.push({ chatId, text: full, kb: [[{text:'Batalkan',callback_data:'m_main'}]] });
} else {
  const chunkSize = 4000;
  for (let i = 0; i < full.length; i += chunkSize) {
    const chunk = full.substring(i, i + chunkSize);
    const isLast = (i + chunkSize) >= full.length;
    msgs.push({ chatId, text: chunk, kb: isLast ? [[{text:'Batalkan',callback_data:'m_main'}]] : null });
  }
}
return msgs.map(m => ({ json: m }));

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const prompt = res.prompt || 'Error: ' + (res.message || 'Gagal generate');
const text = 'PROMPT THUMBNAIL ' + (prev.ratio||'') + ' - ' + (prev.title||'') + '

' + prompt + '

---
Copy lalu paste ke AI image generator.
Upload hasilnya manual di web Adably.';
const kb = [[{text:'Rasio Lain',callback_data:'m_thumb'},{text:'Menu',callback_data:'m_main'}]];
return [{json:{chatId:prev.chatId,text:text.length>4096?text.substring(0,4090)+'...':text,kb}}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const ok = res.success === true;
const id = res.data?.id || '';
const kb = ok ? [[{text:'Submit Review',callback_data:'submit_'+id},{text:'Status',callback_data:'status_'+id}],[{text:'Buka Editor',url:'https://adably.id/admin/editor?id='+id},{text:'Menu',callback_data:'m_main'}]] : [[{text:'Menu',callback_data:'m_main'}]];
const text = ok ? 'Konten tersimpan!\n\nID: '+id+'\nJudul: '+(res.data?.title||'')+'\nStatus: '+(res.data?.status||'')+'\nTipe: '+(res.data?.type||'') : 'Gagal menyimpan: '+(res.message||JSON.stringify(res).substring(0,200));
return [{json:{chatId:prev.chatId,text,kb}}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const text = res.success ? 'Berhasil! ' + (res.message||'') : 'Gagal submit: '+(res.message||'Error');
const kb = [[{text:'Cek Status',callback_data:'status_'+prev.cId},{text:'Menu',callback_data:'m_main'}]];
return [{json:{chatId:prev.chatId,text,kb}}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const d = res.data || {};
const text = res.success ? 'Status Konten

ID: '+(d.id||'-')+'
Judul: '+(d.title||'-')+'
Tipe: '+(d.type||'-')+'
Status: '+(d.status||'-')+'
Update: '+(d.updatedAt?.substring(0,10)||'-') : 'Error: '+(res.message||'Tidak ditemukan');
const kb = res.success ? [[{text:'Submit',callback_data:'submit_'+d.id},{text:'Editor',url:'https://adably.id/admin/editor?id='+d.id}],[{text:'Menu',callback_data:'m_main'}]] : [[{text:'Menu',callback_data:'m_main'}]];
